import React, { useEffect, useState } from 'react';
import { Link } from 'react-router-dom';
import './Navbar.css';
import { FaSearch, FaUser, FaHeart, FaShoppingBag } from "react-icons/fa";

function Navbar() {
  const [cartCount, setCartCount] = useState(0);
  const [wishCount, setWishCount] = useState(0);
  const [showDropdown, setShowDropdown] = useState(false);

  useEffect(() => {
    // 🔹 function to update cart
    const updateCart = () => {
      const cartData = JSON.parse(localStorage.getItem("cart") || "[]");
      setCartCount(cartData.length);
    };

    // 🔹 function to update wishlist
    const updateWishlist = () => {
      const wishData = JSON.parse(localStorage.getItem("wishlist") || "[]");
      setWishCount(wishData.length);
    };

    // Initial call
    updateCart();
    updateWishlist();

    // Listen for cart/wishlist updates
    window.addEventListener("cartUpdated", updateCart);
    window.addEventListener("wishlistUpdated", updateWishlist);

    // Cleanup
    return () => {
      window.removeEventListener("cartUpdated", updateCart);
      window.removeEventListener("wishlistUpdated", updateWishlist);
    };
  }, []);

  return (
    <nav className="navbar">
      {/* Left - Logo */}
      <div className="logo">🧥 CREWS</div>

      {/* Center - Main links */}
      <ul className="nav-links">
        <li><Link to="/">Home</Link></li>
        <li><Link to="/products">Products</Link></li>
        <li><Link to="/about">About Us</Link></li>
        <li><Link to="/contact">Contact</Link></li>
      </ul>

      {/* Right - extra links + search + icons */}
      <div className="navbar-right">
        <Link to="#">Help</Link>
        <Link to="#">Orders</Link>
        <Link to="/signup">Sign Up</Link>
        <Link to="/login">Log In</Link>

        {/* Search box */}
        <div className="search-box">
          <input type="text" placeholder="Search" />
          <FaSearch className="search-icon" />
        </div>

        {/* 👤 User Dropdown */}
        <div className="user-dropdown">
          <FaUser 
            className="icon" 
            onClick={() => setShowDropdown(!showDropdown)} 
          />
          {showDropdown && (
            <div className="dropdown-menu">
              <p><strong>User Profile</strong></p>
              <p>Email: user@example.com</p>
              <hr />
              <Link to="/orders">My Orders</Link>
              <Link to="/wishlist">My Wishlist ❤️</Link>
              <Link to="/cart">My Cart 🛒</Link>
              <Link to="/profile">Account Settings</Link>
              <Link to="/logout">Logout</Link>
            </div>
          )}
        </div>

        {/* ❤️ Wishlist with count */}
        <Link to="/wishlist" className="icon-link">
          <FaHeart className="icon" />
          {wishCount > 0 && <span className="badge">{wishCount}</span>}
        </Link>

        {/* 🛒 Cart with count */}
        <Link to="/cart" className="icon-link">
          <FaShoppingBag className="icon" />
          {cartCount > 0 && <span className="badge">{cartCount}</span>}
        </Link>
      </div>
    </nav>
  );
}

export default Navbar;
